class Solution:
    def canReach(self, arr, start):
        """
        :type arr: List[int]
        :type start: int
        :rtype: bool
        """
        visited = set()
        queue = deque([start])
        visited.add(start)

        while queue:
            idx = queue.popleft()

            if arr[idx] == 0:
                return True

            # Try both jump directions
            for next_idx in [idx + arr[idx], idx - arr[idx]]:
                if 0 <= next_idx < len(arr) and next_idx not in visited:
                    visited.add(next_idx)
                    queue.append(next_idx)

        return False
